class BSTIterator:
    def __init__(self, root: Optional[TreeNode]):
        self.st = []
        self._left(root)
    def _left(self, node):
        while node:
            self.st.append(node)
            node = node.left
    def next(self) -> int:
        node = self.st.pop()
        self._left(node.right)
        return node.val
    def hasNext(self) -> bool:
        return bool(self.st)

